const CODE_TABS = ['python', 'javascript', 'fastapi', 'express', 'curl'];
const PRIORITY_COLORS = {
  primary: { bg: 'var(--color-gold-light)', color: 'var(--color-gold-dark)' },
  secondary: { bg: 'var(--color-stone)', color: 'var(--color-text-muted)' },
  optional: { bg: 'var(--color-surface)', color: 'var(--color-text-muted)' },
};

function useCopy() {
  const [copied, setCopied] = useState(false);
  const copy = (text) => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    });
  };
  return [copied, copy];
}

export default function BuildPilot() {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [blueprint, setBlueprint] = useState(null);
  const [examples, setExamples] = useState([]);
  const [activeTab, setActiveTab] = useState('python');
  const blueprintRef = useRef(null);
  const [copied, copy] = useCopy();

  useEffect(() => {
    buildPilotApi.examples()
      .then(r => setExamples(r.data || []))
      .catch(() => {});
  }, []);

  const analyze = async () => {
    if (!input.trim() || input.trim().length < 5) {
      setError('Please describe what you are building (minimum 5 characters).');
      return;
    }
    setError('');
    setLoading(true);
    setBlueprint(null);
    try {
      const result = await buildPilotApi.analyze(input.trim());
      setBlueprint(result.data);
      setTimeout(() => blueprintRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
    } catch (e) {
      setError(e.message || 'Analysis failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleKey = (e) => {
    if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) analyze();
  };

  return (
    <div style={S.page} className="page-enter">
      {/* Hero */}
      <div style={S.hero}>
        <div style={S.heroInner}>
          <div style={S.badge}>⭐ Flagship Feature</div>
          <h1 style={S.title}>BuildPilot</h1>
          <p style={S.subtitle}>
            Tell us what you're building. We'll recommend the perfect dataset stack,
            generate integration code, and get you from idea to API call.
          </p>
        </div>
      </div>

      {/* Input Area */}
      <div style={S.inputArea}>
        <textarea
          id="buildpilot-input"
          style={S.textarea}
          placeholder="I'm building a Hospital Finder application for patients to locate nearby facilities..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={handleKey}
          onFocus={e => { e.target.style.borderColor = 'var(--color-gold)'; e.target.style.boxShadow = 'var(--shadow-gold)'; }}
          onBlur={e => { e.target.style.borderColor = 'var(--color-stone)'; e.target.style.boxShadow = 'none'; }}
          maxLength={500}
        />
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 6 }}>
          <span style={{ fontSize: 'var(--text-xs)', color: 'var(--color-text-muted)' }}>Ctrl+Enter to analyze</span>
          <span style={{ fontSize: 'var(--text-xs)', color: input.length > 450 ? 'var(--color-warning)' : 'var(--color-text-muted)' }}>
            {input.length}/500
          </span>
        </div>
        {error && <div style={S.error}>{error}</div>}
        <button
          id="buildpilot-analyze-btn"
          className="btn btn-gold btn-lg"
          style={{ width: '100%', marginTop: 14, fontSize: 'var(--text-base)' }}
          onClick={analyze}
          disabled={loading}
        >
          {loading ? (
            <><span className="spinner spinner-sm" style={{ borderTopColor: '#fff', borderColor: 'rgba(255,255,255,0.3)' }} /> Analyzing...</>
          ) : '🧠 Analyze My Project'}
        </button>
      </div>

      {/* Examples */}
      <div style={S.examplesSection}>
        <div style={S.examplesLabel}>Try an example</div>
        <div style={S.examplesRow}>
          {examples.slice(0, 8).map((ex, i) => (
            <button key={i} style={S.chip} onClick={() => setInput(ex)}
              onMouseEnter={e => { e.target.style.background = 'var(--color-gold-light)'; e.target.style.borderColor = 'var(--color-gold)'; e.target.style.color = 'var(--color-gold-dark)'; }}
              onMouseLeave={e => { e.target.style.background = 'var(--color-surface)'; e.target.style.borderColor = 'var(--color-stone)'; e.target.style.color = 'var(--color-text-secondary)'; }}>
              {ex.replace("I'm building ", '').replace(/\.$/, '')}
            </button>
          ))}
        </div>
      </div>

      {/* Blueprint Output */}
      {loading && (
        <div style={S.blueprint}>
          <div style={{ ...S.bpHeader, background: 'var(--color-surface)' }}>
            <div style={{ width: '60%', height: 32, borderRadius: 8, marginBottom: 14 }} className="skeleton" />
            <div style={{ display: 'flex', gap: 8 }}>
              {[80, 100, 60].map((w, i) => (
                <div key={i} style={{ width: w, height: 22, borderRadius: 99 }} className="skeleton" />
              ))}
            </div>
          </div>
          {[1, 2, 3].map(i => (
            <div key={i} style={{ height: 80, borderRadius: 12, marginBottom: 16 }} className="skeleton" />
          ))}
        </div>
      )}

      {blueprint && (
        <div style={S.blueprint} ref={blueprintRef} className="animate-fade-in-up">

          {/* Header */}
          <div style={S.bpHeader}>
            <div style={S.bpProjectType}>{blueprint.project_type}</div>
            <div style={S.badgeRow}>
              <span className="badge badge-gold">{blueprint.detected_domain}</span>
              <span className="badge badge-default">{blueprint.difficulty}</span>
              <span className="badge badge-emerald">⏱ {blueprint.estimated_integration_time}</span>
              {blueprint._source === 'ai' && <span className="badge badge-default">✨ AI Blueprint</span>}
            </div>
          </div>

          {/* Summary */}
          <div style={S.bpSummary}>
            <p style={{ ...S.bpSummaryText, fontWeight: 'var(--weight-medium)', marginBottom: 8, color: 'var(--color-text-primary)' }}>Project Summary</p>
            <p style={S.bpSummaryText}>{blueprint.summary}</p>
          </div>

          {/* Recommended Datasets */}
          {blueprint.recommended_datasets?.length > 0 && (
            <>
              <h2 style={S.sectionHead}>📦 Recommended Datasets</h2>
              <div style={S.dsGrid}>
                {blueprint.recommended_datasets.map((ds, i) => {
                  const pColor = PRIORITY_COLORS[ds.priority] || PRIORITY_COLORS.optional;
                  return (
                    <div key={i} style={S.dsCard}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
                        <div style={S.dsSlug}>{ds.slug}</div>
                        <span style={{ padding: '2px 10px', background: pColor.bg, color: pColor.color, borderRadius: 'var(--radius-full)', fontSize: 'var(--text-xs)', fontWeight: 600, whiteSpace: 'nowrap' }}>
                          {ds.priority}
                        </span>
                      </div>
                      <div style={S.dsReason}>{ds.reason}</div>
                      <div style={S.dsUsage}>{ds.usage}</div>
                      <Link to={`/datasets/${ds.slug}`} className="btn btn-outline btn-sm">View Dataset →</Link>
                    </div>
                  );
                })}
              </div>
            </>
          )}

          {/* Quick Start */}
          {blueprint.quick_start?.length > 0 && (
            <>
              <h2 style={S.sectionHead}>🚀 Quick Start</h2>
              <div style={S.stepsBox}>
                {blueprint.quick_start.map((step, i) => (
                  <div key={i} style={{ ...S.step, marginBottom: i < blueprint.quick_start.length - 1 ? 14 : 0 }}>
                    <div style={S.stepCircle}>{i + 1}</div>
                    <div style={S.stepText}>{step}</div>
                  </div>
                ))}
              </div>
            </>
          )}

          {/* Code Examples */}
          {blueprint.code_examples && (
            <>
              <h2 style={S.sectionHead}>💻 Code Examples</h2>
              <div style={{ marginBottom: 32 }}>
                <div style={S.tabBar}>
                  {CODE_TABS.filter(t => blueprint.code_examples[t]).map(t => (
                    <button key={t} style={{ ...S.tab, ...(activeTab === t ? S.tabActive : {}) }} onClick={() => setActiveTab(t)}>
                      {t}
                    </button>
                  ))}
                </div>
                <div style={S.codeBox}>
                  <button style={S.copyBtn} onClick={() => copy(blueprint.code_examples[activeTab])}>
                    {copied ? '✓ Copied' : 'Copy'}
                  </button>
                  <pre style={S.codePre}>{blueprint.code_examples[activeTab]}</pre>
                </div>
              </div>
            </>
          )}

          {/* Suggested Filters */}
          {blueprint.suggested_filters?.length > 0 && (
            <>
              <h2 style={S.sectionHead}>🔧 Suggested Filters</h2>
              <div style={S.filtersRow}>
                {blueprint.suggested_filters.map((f, i) => (
                  <span key={i} style={S.filterTag}>{f}</span>
                ))}
              </div>
            </>
          )}

          {/* Actions */}
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', paddingTop: 24, borderTop: '1px solid var(--color-stone)' }}>
            <Link to="/explore" className="btn btn-primary">Explore Datasets</Link>
            <Link to="/console" className="btn btn-outline">Open API Console</Link>
            <button className="btn btn-ghost" onClick={() => { setBlueprint(null); setInput(''); window.scrollTo({ top: 0, behavior: 'smooth' }); }}>
              Analyze Another Project
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
